// ═══════════════════════════════════════════════════════════
// KONFIGURATION – Pfade hier anpassen
// ═══════════════════════════════════════════════════════════
const fs = global.get('fs');
const path = global.get('path');

const AASX_DIR    = 'P:\\02_Lehrstuhl\\SHK Studentische Hilfskräfte\\de Buhr\\Carmen\\Technical_Data_erweitert';
const XLSX_PATH   = 'P:\\02_Lehrstuhl\\SHK Studentische Hilfskräfte\\de Buhr\\Carmen\\Beispiel_Ema_Exportdatei.xlsx';
const AAS_PATH    = AASX_DIR + '\\aasx\\aasenv-with-no-id\\aasenv-with-no-id.aas.xml';
const FILES_DIR   = AASX_DIR + '\\aasx\\files';
const AASX_OUTPUT = 'P:\\02_Lehrstuhl\\SHK Studentische Hilfskräfte\\de Buhr\\Carmen\\Technical_Data_erweitert.aasx';
const XLSX_FNAME  = path.basename(XLSX_PATH);

// ═══════════════════════════════════════════════════════════
// Erstelldatum der XLSX-Datei = time_of_simulation
// ═══════════════════════════════════════════════════════════
let timeOfSim = new Date().toISOString();
try {
    const stats = fs.statSync(XLSX_PATH);
    const birthtime = stats.birthtime;
    timeOfSim = (birthtime && birthtime.getFullYear() > 1970)
        ? birthtime.toISOString()
        : stats.mtime.toISOString();
    node.log('[Metadaten] time_of_simulation = ' + timeOfSim);
} catch (e) {
    node.warn('[Metadaten] Erstelldatum nicht lesbar, verwende aktuelles Datum. ' + e.message);
}

// ═══════════════════════════════════════════════════════════
// xlsx-to-json Node Parameter (per msg übergeben)
// ═══════════════════════════════════════════════════════════
msg.filepath  = XLSX_PATH;
msg.filename  = XLSX_PATH;
msg.rangecell = 'B5:F36';
msg.range     = 'B5:F36';
msg.sheet     = '2025 - Medienverbrauch';
msg.columnkey = JSON.stringify({
    "B": "Arbeitsplatz",
    "C": "Verbrauch, Strom",
    "F": "Verbrauch, Wasser"
});

// Alle Pfade im Flow-Kontext speichern
flow.set('time_of_simulation', timeOfSim);
flow.set('aas_path',     AAS_PATH);
flow.set('xlsx_path',    XLSX_PATH);
flow.set('xlsx_filename', XLSX_FNAME);
flow.set('files_dir',    FILES_DIR);
flow.set('aasx_dir',     AASX_DIR);
flow.set('aasx_output',  AASX_OUTPUT);

node.status({ fill: 'blue', shape: 'dot', text: 'time_of_sim: ' + timeOfSim.substring(0, 10) });
return msg;

// ═══════════════════════════════════════════════════════════
// msg.payload = Array von Row-Objekten vom xlsx-Node
// ═══════════════════════════════════════════════════════════

if (!msg.payload || !Array.isArray(msg.payload)) {
    node.error('Ungültiges Excel-Format – msg.payload ist kein Array', msg);
    return null;
}

// Leere Zeilen und Zeilen ohne Arbeitsplatz herausfiltern
const rawRows = msg.payload.filter(row =>
    row['Arbeitsplatz'] && String(row['Arbeitsplatz']).trim() !== ''
);

if (rawRows.length === 0) {
    node.warn('Keine gültigen Datenzeilen gefunden. Prüfe Bereich B5:F36 und Sheet-Name.');
    return null;
}

// ── AAS-konformer idShort  ────────────────────────────────────────────────
// Constraint AASd-002: idShort shall match [a-zA-Z][a-zA-Z0-9_]*
//   • Nur Buchstaben, Ziffern, Unterstrich erlaubt (kein Bindestrich!)
//   • Erstes Zeichen MUSS ein Buchstabe sein → Präfix 'AP_' falls nicht
function toIdShort(name) {
    // 1. Umlaute semantisch ersetzen für die idShort
    let s = name
        .replace(/ä/g, 'ae')
        .replace(/ö/g, 'oe')
        .replace(/ü/g, 'ue')
        .replace(/Ä/g, 'Ae')
        .replace(/Ö/g, 'Oe')
        .replace(/Ü/g, 'Ue')
        .replace(/ß/g, 'ss');
    // 2. Alle nicht erlaubten Zeichen (inkl. '-' und ' ') → '_'
    name = name.replace(/[^a-zA-Z0-9_]/g, '_');
    // 3. Führende Unterstriche / Ziffern mit 'AP_' präfixieren
    if (!/^[a-zA-Z]/.test(s)) s = 'AP_' + s;
    // 4. Doppelte Unterstriche bereinigen (optional, für Lesbarkeit)
    s = s.replace(/__+/g, '_').replace(/_$/, '');
    // 5. Maximal 255 Zeichen
    return s.substring(0, 255);
}

// Daten normalisieren
const parseNum = v => parseFloat(String(v || '0').replace(',', '.')) || 0;

const processes = rawRows.map(row => {
    const ap = String(row['Arbeitsplatz']).trim();
    return {
        Arbeitsplatz:     ap,
        idShort:          toIdShort(ap),
        Verbrauch_Strom:  parseNum(row['Verbrauch, Strom']  || row['Verbrauch_Strom']),
        Verbrauch_Wasser: parseNum(row['Verbrauch, Wasser'] || row['Verbrauch_Wasser'])
    };
});

node.log('[Verarbeitung] ' + processes.length + ' Arbeitsplätze: ' +
    processes.map(p => '"' + p.Arbeitsplatz + '" → ' + p.idShort).join(', '));

flow.set('ema_processes', processes);
msg.payload = { processes };

node.status({ fill: 'green', shape: 'dot', text: processes.length + ' Arbeitsplätze verarbeitet' });
return msg;

// ═══════════════════════════════════════════════════════════
// HILFSFUNKTIONEN (xml2js-Format: Werte stets in Arrays)
// ═══════════════════════════════════════════════════════════

/** Sucht in einem Array von xml2js-Elementen nach idShort */
function findByIdShort(arr, idShort) {
    if (!Array.isArray(arr)) return null;
    return arr.find(el => el.idShort && el.idShort[0] === idShort) || null;
}

/** Erstellt/Aktualisiert eine AAS Property im propArray */
function upsertProperty(propArray, idShort, value, valueType) {
    let prop = findByIdShort(propArray, idShort);
    if (!prop) {
        propArray.push({ idShort: [idShort], valueType: [valueType], value: [String(value)] });
        node.log('[AAS] Property angelegt: ' + idShort + ' = ' + value);
    } else {
        prop.value     = [String(value)];
        prop.valueType = [valueType];
        node.log('[AAS] Property aktualisiert: ' + idShort + ' = ' + value);
    }
}

// ═══════════════════════════════════════════════════════════
// DATEN AUS FLOW-KONTEXT
// ═══════════════════════════════════════════════════════════
const environment  = msg.payload.environment;
const timeOfSim    = flow.get('time_of_simulation') || new Date().toISOString();
const emaProcesses = flow.get('ema_processes') || [];
const xlsxFname    = flow.get('xlsx_filename') || '';

if (!environment || !environment.submodels) {
    node.error("Ungültige XML-Struktur: 'environment.submodels' nicht gefunden."); return null;
}

// ═══════════════════════════════════════════════════════════
// NAVIGATION: TechnicalData → Data Sources → Simulation
// ═══════════════════════════════════════════════════════════
const submodels = environment.submodels[0].submodel;
const techData  = findByIdShort(submodels, 'TechnicalData');
if (!techData) { node.error("Submodell 'TechnicalData' nicht gefunden."); return null; }

const smElemContainer = techData.submodelElements[0];

const dataSourcesList = findByIdShort(smElemContainer.submodelElementList, 'Data Sources');
if (!dataSourcesList || !dataSourcesList.value) {
    node.error("SubmodelElementList 'Data Sources' nicht gefunden."); return null;
}

const dsValueContainer = dataSourcesList.value[0];
if (!dsValueContainer.submodelElementCollection) {
    node.error("Keine SubmodelElementCollections in 'Data Sources'."); return null;
}

const simulationSmc = findByIdShort(dsValueContainer.submodelElementCollection, 'Simulation');
if (!simulationSmc || !simulationSmc.value) {
    node.error("SMC 'Simulation' nicht gefunden."); return null;
}

// simValueContainer enthält property[], file[], submodelElementList[], submodelElementCollection[]
const simValueContainer = simulationSmc.value[0];
if (!simValueContainer.property)                   simValueContainer.property = [];
if (!simValueContainer.file)                       simValueContainer.file     = [];
if (!simValueContainer.submodelElementCollection)  simValueContainer.submodelElementCollection = [];

// ═══════════════════════════════════════════════════════════
// time_of_simulation (Property, Geschwister von Simulation_Processes)
// ═══════════════════════════════════════════════════════════
upsertProperty(simValueContainer.property, 'time_of_simulation', timeOfSim, 'xs:dateTime');

// ═══════════════════════════════════════════════════════════
// export_file (File-Element, Geschwister von Simulation_Processes)
// Interner AASX-Pfad: /aasx/files/<dateiname>
// ═══════════════════════════════════════════════════════════
let exportFile = findByIdShort(simValueContainer.file, 'export_file');
if (!exportFile) {
    exportFile = { idShort: ['export_file'], contentType: [''], value: [''] };
    simValueContainer.file.push(exportFile);
    node.log('[AAS] file[export_file] neu angelegt');
}
exportFile.contentType = ['application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'];
exportFile.value       = ['/aasx/files/' + xlsxFname];
node.log('[AAS] export_file → /aasx/files/' + xlsxFname);

// ═══════════════════════════════════════════════════════════
// Simulation_Processes als SubmodelElementCOLLECTION anlegen
// ─────────────────────────────────────────────────────────
// WICHTIG: Nicht als submodelElementList, weil sonst:
//   AASd-120: Kinder dürfen kein idShort haben
//   AASd-108: Kinder müssen expliziten SubmodelElement-Typ haben
// Als SubmodelElementCollection darf jedes Kind ein idShort tragen.
// ═══════════════════════════════════════════════════════════

// Falls Simulation_Processes noch als submodelElementList existiert (alt):
// → aus der Liste entfernen, wird unten als Collection neu angelegt
if (simValueContainer.submodelElementList) {
    const oldIdx = simValueContainer.submodelElementList
        .findIndex(el => el.idShort && el.idShort[0] === 'Simulation_Processes');
    if (oldIdx !== -1) {
        simValueContainer.submodelElementList.splice(oldIdx, 1);
        node.log('[AAS] Simulation_Processes aus submodelElementList entfernt (Migration → Collection)');
    }
}

// In submodelElementCollection suchen oder neu anlegen
let simProcSmc = findByIdShort(simValueContainer.submodelElementCollection, 'Simulation_Processes');
if (!simProcSmc) {
    simProcSmc = { idShort: ['Simulation_Processes'], value: [{ submodelElementCollection: [] }] };
    simValueContainer.submodelElementCollection.push(simProcSmc);
    node.log('[AAS] SubmodelElementCollection[Simulation_Processes] neu angelegt');
}
if (!simProcSmc.value)                                         simProcSmc.value = [{}];
if (!simProcSmc.value[0].submodelElementCollection)            simProcSmc.value[0].submodelElementCollection = [];

const procArray = simProcSmc.value[0].submodelElementCollection;

// ═══════════════════════════════════════════════════════════
// Je Arbeitsplatz: SubmodelElementCollection mit Properties
// idShort ist hier erlaubt (wir sind in einer SMC, nicht SML)
// ═══════════════════════════════════════════════════════════
let addedCount = 0;
for (const proc of emaProcesses) {
    let apSmc = findByIdShort(procArray, proc.idShort);
    if (!apSmc) {
        apSmc = { idShort: [proc.idShort], value: [{ property: [] }] };
        procArray.push(apSmc);
        node.log('[AAS] SMC angelegt: ' + proc.idShort);
    }
    if (!apSmc.value[0].property) apSmc.value[0].property = [];
    upsertProperty(apSmc.value[0].property, 'Verbrauch_Strom',  proc.Verbrauch_Strom,  'xs:float');
    upsertProperty(apSmc.value[0].property, 'Verbrauch_Wasser', proc.Verbrauch_Wasser, 'xs:float');
    addedCount++;
}

node.log('[AAS] ' + addedCount + ' Arbeitsplätze, time_of_simulation, export_file gesetzt.');
node.status({ fill: 'green', shape: 'dot', text: addedCount + ' AP + export_file + time_of_sim ✓' });
return msg;

const fs = global.get('fs');
const aasPath = flow.get('aas_path');

try {
    fs.writeFileSync(aasPath, msg.payload, 'utf8');
    node.log('[Speichern] AAS XML gespeichert: ' + aasPath);
    node.status({ fill: 'green', shape: 'dot', text: '✓ XML gespeichert ' + new Date().toLocaleTimeString('de-DE') });
} catch (e) {
    node.error('[Speichern] Fehler: ' + e.message, msg);
    node.status({ fill: 'red', shape: 'dot', text: 'Fehler beim Speichern!' });
    return null;
}
return msg;

const fs    = global.get('fs');
const path  = global.get('path');

const aasx_dir  = flow.get('aasx_dir');
const filesDir  = flow.get('files_dir');
const xlsxPath  = flow.get('xlsx_path');
const xlsxFname = flow.get('xlsx_filename');

// ── 1. xlsx in aasx/files/ kopieren ─────────────────────────────────────────
try {
    if (!fs.existsSync(filesDir)) {
        fs.mkdirSync(filesDir, { recursive: true });
        node.log('[Kopieren] Ordner erstellt: ' + filesDir);
    }
    const dest = path.join(filesDir, xlsxFname);
    fs.copyFileSync(xlsxPath, dest);
    node.log('[Kopieren] xlsx → ' + dest);
    node.status({ fill: 'blue', shape: 'dot', text: xlsxFname + ' → aasx/files/' });
} catch (e) {
    node.error('[Kopieren] Fehler: ' + e.message, msg);
    node.status({ fill: 'red', shape: 'dot', text: 'Kopieren fehlgeschlagen!' });
    return null;
}

// ── 2. [Content_Types].xml patchen ──────────────────────────────────────────
// AASX basiert auf OPC (Open Packaging Convention). Jede Datei im Paket MUSS
// dort mit ihrem MIME-Typ registriert sein, sonst lehnen BaSyx und andere
// konforme Viewer das Paket mit einem Parse-Fehler ab.
try {
    const ctPath = path.join(aasx_dir, '[Content_Types].xml');

    if (!fs.existsSync(ctPath)) {
        node.warn('[ContentTypes] [Content_Types].xml nicht gefunden: ' + ctPath);
    } else {
        let ctXml = fs.readFileSync(ctPath, 'utf8');
        node.log('[ContentTypes] Gelesen: ' + ctPath);

        const xlsxMime    = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
        const xlsxExt     = 'xlsx';

        // Prüfen ob xlsx bereits als Default-Extension oder Override registriert ist
        const hasDefault  = new RegExp(`Extension="${xlsxExt}"`).test(ctXml);
        const hasOverride = ctXml.includes('/aasx/files/' + xlsxFname);

        if (!hasDefault && !hasOverride) {
            // Als Default-Extension eintragen (gilt für alle .xlsx-Dateien im Paket)
            // Einfügen vor dem schließenden </Types>-Tag
            const entry = `  <Default Extension="${xlsxExt}" ContentType="${xlsxMime}" />\n`;
            ctXml = ctXml.replace('</Types>', entry + '</Types>');
            fs.writeFileSync(ctPath, ctXml, 'utf8');
            node.log('[ContentTypes] Eintrag für .xlsx hinzugefügt: ' + xlsxMime);
        } else {
            node.log('[ContentTypes] .xlsx bereits registriert – kein Update nötig.');
        }

        node.status({ fill: 'green', shape: 'dot', text: '✓ xlsx kopiert + ContentTypes gepatcht' });
    }
} catch (e) {
    node.warn('[ContentTypes] Fehler beim Patchen: ' + e.message);
    // Kein return null – xlsx-Kopie war erfolgreich, Flow soll weiterlaufen
}

return msg;

// Rohen XML-String vor dem Parsen im Flow-Kontext speichern.
// Wird nach dem AASX-Packen für den Cleanup-Reset benötigt.
flow.set('original_xml', msg.payload);
node.log('[Backup] Original-XML gesichert (' + msg.payload.length + ' Zeichen)');
node.status({ fill: 'grey', shape: 'ring', text: 'XML gesichert' });
return msg;

const fs = global.get('fs');
const os = global.get('os');
const path = global.get('path');
const child_process = global.get('child_process');
const { execFileSync } = child_process;

const aasx_dir = flow.get('aasx_dir');
const aasx_out = flow.get('aasx_output');

try {
    // Sicherstellen, dass der Zielordner existiert
    const outDir = path.dirname(aasx_out);
    if (!fs.existsSync(outDir)) {
        fs.mkdirSync(outDir, { recursive: true });
    }

    // PowerShell-Skript mit verbesserter Pfad-Behandlung
    // Wir nutzen hier Single-Quotes für die Pfade in PS, um Probleme mit Sonderzeichen zu minimieren
    const psLines = [
        '$ErrorActionPreference = "Stop"',
        'try {',
        '    Add-Type -Assembly "System.IO.Compression.FileSystem"',
        '    $src = \'' + aasx_dir + '\'',
        '    $dst = \'' + aasx_out + '\'',
        '    if (Test-Path $dst) { Remove-Item $dst -Force }',
        '    [System.IO.Compression.ZipFile]::CreateFromDirectory($src, $dst)',
        '    Write-Host "SUCCESS"',
        '} catch {',
        '    Write-Error $_.Exception.Message',
        '    exit 1',
        '}'
    ];

    const tmpScript = path.join(os.tmpdir(), 'pack_aasx_' + Date.now() + '.ps1');

    // WICHTIG: Wir schreiben die Datei explizit mit UTF-8, 
    // aber wir fügen eine Zeile für PowerShell hinzu, um Umlaute zu handhaben.
    fs.writeFileSync(tmpScript, psLines.join('\r\n'), 'utf8');

    const out = execFileSync('powershell', [
        '-NoProfile', 
        '-ExecutionPolicy', 'Bypass', 
        '-Command', `Get-Content '${tmpScript}' -Encoding UTF8 | Out-String | Invoke-Expression`
    ], { timeout: 30000, encoding: 'utf8' });

    if (fs.existsSync(tmpScript)) { fs.unlinkSync(tmpScript); }

    if (fs.existsSync(aasx_out)) {
        const stats = fs.statSync(aasx_out);
        node.status({ fill: 'green', shape: 'dot', text: '✓ AASX fertig (' + Math.round(stats.size/1024) + ' KB)' });
    } else {
        throw new Error('Datei wurde trotz SUCCESS-Meldung nicht gefunden.');
    }

} catch (e) {
    node.error('[AASX] Pack-Fehler: ' + e.message, msg);
    node.status({ fill: 'red', shape: 'dot', text: 'Pfad- oder Encoding-Fehler!' });
    return null;
}

return msg;

const fs = global.get('fs');
const path = global.get('path');
const errors = [];

// 1. aasx/files/ Ordner entfernen (enthält die kopierte xlsx)
const filesDir = flow.get('files_dir');
try {
    if (fs.existsSync(filesDir)) {
        fs.rmSync(filesDir, { recursive: true, force: true });
        node.log('[Cleanup] aasx/files/ entfernt: ' + filesDir);
    }
} catch (e) {
    const m = 'Fehler beim Löschen von aasx/files/: ' + e.message;
    node.warn('[Cleanup] ' + m); errors.push(m);
}

// 2. Original-XML (leere Werte) wiederherstellen
const originalXml = flow.get('original_xml');
const aasPath     = flow.get('aas_path');
try {
    if (originalXml && aasPath) {
        fs.writeFileSync(aasPath, originalXml, 'utf8');
        node.log('[Cleanup] Original-XML wiederhergestellt: ' + aasPath);
    } else {
        node.warn('[Cleanup] Kein gesichertes Original-XML vorhanden!');
        errors.push('Kein Original-XML im Flow-Kontext');
    }
} catch (e) {
    const m = 'Fehler beim XML-Restore: ' + e.message;
    node.warn('[Cleanup] ' + m); errors.push(m);
}

// 3. [Content_Types].xml: xlsx-Eintrag wieder entfernen
const aasx_dir = flow.get('aasx_dir');
try {
    const ctPath = path.join(aasx_dir, '[Content_Types].xml');
    if (fs.existsSync(ctPath)) {
        let ctXml = fs.readFileSync(ctPath, 'utf8');
        // Den von uns hinzugefügten Default-Eintrag für xlsx entfernen
        const before = ctXml;
        ctXml = ctXml.replace(/\s*<Default Extension="xlsx"[^\/]*\/>\n?/g, '\n');
        if (ctXml !== before) {
            fs.writeFileSync(ctPath, ctXml, 'utf8');
            node.log('[Cleanup] xlsx-Eintrag aus [Content_Types].xml entfernt');
        } else {
            node.log('[Cleanup] [Content_Types].xml – kein xlsx-Eintrag gefunden (ok)');
        }
    }
} catch (e) {
    const m = 'Fehler beim ContentTypes-Restore: ' + e.message;
    node.warn('[Cleanup] ' + m); errors.push(m);
}

if (errors.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: '✓ Urstand hergestellt' });
} else {
    node.status({ fill: 'yellow', shape: 'dot', text: 'Cleanup (' + errors.length + ' Warnung(en))' });
}

msg.result = {
    success:     errors.length === 0,
    aasx_output: flow.get('aasx_output'),
    timestamp:   new Date().toISOString(),
    errors
};
return msg;

// ═══════════════════════════════════════════════════════════
// FIX 1: Namespace-Korrektur
// xml2js serialisiert xmlns manchmal als xmlns:ns0="..." und
// ändert die Versionsnummer (3/1 statt 3/0 des Originals).
// ═══════════════════════════════════════════════════════════
let xmlStr = msg.payload;

// a) Jegliche xmlns-Deklarationen am Root-Tag entfernen
xmlStr = xmlStr.replace(/\s+xmlns(?::\w+)?="[^"]*"/g, '');

// b) ns0: / ns1: Präfixe an Tag-Namen entfernen (xml2js-Artefakt)
xmlStr = xmlStr.replace(/<(\/?)ns\d+:/g, '<$1');

// c) Korrekten AAS-3/0-Namespace als Default-Namespace am Root einfügen
xmlStr = xmlStr.replace(
    /(<environment)(\s|>)/,
    '$1 xmlns="https://admin-shell.io/aas/3/0"$2'
);

node.log('[FixXML] Namespace: https://admin-shell.io/aas/3/0 gesetzt');

// ═══════════════════════════════════════════════════════════
// FIX 2: Leere Listen entfernen
// aas-test-engines: "Empty list not allowed @ .../description"
// xml2js parst <description/> zu description:[] oder description:[{}]
// und serialisiert das zu <description></description> → Validierungsfehler.
// ═══════════════════════════════════════════════════════════
const EMPTY_TAGS = [
    'description', 'displayName', 'extension',
    'embeddedDataSpecifications', 'qualifiers', 'annotations'
];

for (const tag of EMPTY_TAGS) {
    // <tag/>  und  <tag />
    xmlStr = xmlStr.replace(new RegExp(`<${tag}\\s*/>`, 'g'), '');
    // <tag></tag>  und  <tag>   </tag>
    xmlStr = xmlStr.replace(new RegExp(`<${tag}[^>]*>\\s*</${tag}>`, 'g'), '');
}

node.log('[FixXML] Leere Listen bereinigt: ' + EMPTY_TAGS.join(', '));
node.status({ fill: 'green', shape: 'dot', text: 'Fix OK – ' + xmlStr.length + ' Zeichen' });

msg.payload = xmlStr;
return msg;
